import React, { useState, useEffect } from 'react';

const EditCombinedMaterial = ({
  materialId,
  onClose,
  fetchAPI,
  apiBaseUrl,
  onMaterialUpdated,
}) => {
  const [materialData, setMaterialData] = useState({
    name: '',
    description: '',
    submaterials: [],
  });
  const [error, setError] = useState(null);
  const [allMaterials, setAllMaterials] = useState([]); // For dropdown selection of submaterials
  console.log('editedcomb',materialData);
  // Fetching all available materials for submaterial selection
  useEffect(() => {
    const fetchAllMaterials = async () => {
      try {
        const materials = await fetchAPI(`${apiBaseUrl}/materiallist`);
        setAllMaterials(materials);
      } catch (error) {
        setError(error.message);
      }
    };

    fetchAllMaterials();
  }, [fetchAPI, apiBaseUrl]);

  // Fetching specific combined material data for editing
  useEffect(() => {
    const fetchMaterialData = async () => {
      try {
        const data = await fetchAPI(`${apiBaseUrl}/combinedMaterials/${materialId}`);
        setMaterialData(data); // Assuming the API returns the material with its submaterials
      } catch (error) {
        setError(error.message);
      }
    };

    fetchMaterialData();
  }, [materialId, fetchAPI, apiBaseUrl]);

  // Handlers for updating material data
  const handleMaterialChange = (e) => {
    const { name, value } = e.target;
    setMaterialData((prevData) => ({
      ...prevData,
      [name]: value,
    }));
  };

  const handleSubmaterialChange = (index, field, value) => {
    const updatedSubmaterials = [...materialData.submaterials];
    updatedSubmaterials[index] = {
      ...updatedSubmaterials[index],
      [field]: value,
    };
    setMaterialData({ ...materialData, submaterials: updatedSubmaterials });
  };

  const addSubmaterial = () => {
    setMaterialData({
      ...materialData,
      submaterials: [...materialData.submaterials, { material_id: '', multiplier: 0 }],
    });
  };

  const removeSubmaterial = (index) => {
    const filteredSubmaterials = materialData.submaterials.filter((_, i) => i !== index);
    setMaterialData({ ...materialData, submaterials: filteredSubmaterials });
  };

  const saveChanges = async () => {
    try {
      await await fetchAPI(`${apiBaseUrl}/saveCombinedMaterial/${materialId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(materialData),
      });
      onMaterialUpdated(); // Notify parent component to refresh the list or close the edit mode
      onClose(); // Close the edit form
    } catch (error) {
      setError(error.message);
    }
  };

  return (
    <div className="edit-combined-material">
      <h3>Edit Combined Material</h3>
      {error && <div>Error: {error}</div>}
      <div>
        <label htmlFor="name">Name:</label>
        <input
          id="name"
          name="name"
          value={materialData.name}
          onChange={handleMaterialChange}
        />
      </div>
      <div>
        <label htmlFor="description">Description:</label>
        <textarea
          id="description"
          name="description"
          value={materialData.description}
          onChange={handleMaterialChange}
        />
      </div>
      <div>
        <h4>Submaterials:</h4>
        {materialData.submaterials.map((submat, index) => (
          <div key={index}>
            <select
              value={submat.material_id}
              onChange={(e) => handleSubmaterialChange(index, 'maaterial_id', e.target.value)}
            >
              <option value="">Select Material</option>
              {allMaterials.map((mat) => (
                <option key={mat.id} value={mat.id}>
                  {mat.name}
                </option>
              ))}
            </select>
            <input
              type="number"
              value={submat.multiplier}
              onChange={(e) => handleSubmaterialChange(index, 'multiplier', e.target.value)}
            />
            <button onClick={() => removeSubmaterial(index)}>Remove</button>
          </div>
        ))}
        <button onClick={addSubmaterial}>Add Submaterial</button>
      </div>
      <button onClick={saveChanges}>Save Changes</button>
      <button onClick={onClose}>Close</button>
    </div>
  );
};

export default EditCombinedMaterial;
